24	const props = defineProps<{ value?: string | null; placeholder?: string | null }>()
25	const emit = defineEmits<{ save: [value: string]; dblclick: [] }>()
26	
27	const editing = ref(false)
28	const editValue = ref('')
29	const inputRef = ref<HTMLInputElement | null>(null)
30	
31	function startEdit() {
32	  emit('dblclick')
33	  editing.value = true
34	  editValue.value = props.value || ''
35	  nextTick(() => inputRef.value?.focus())
36	}
37	
38	function save() {
39	  if (!editing.value) return
40	  editing.value = false
41	  if (editValue.value !== (props.value || '')) {
42	    emit('save', editValue.value)
43	  }
44	}
45	
46	function cancel() {
47	  editing.value = false
48	}
